struct NumberGenerator {
    start: u32,
}

impl Iterator for NumberGenerator {
    type Item = u32;

    fn next(&mut self) -> Option<Self::Item> {
        let val = self.start;
        self.start += 1;
        Some(val)
    }
}

fn main() {
    let gen = NumberGenerator { start: 10 };

    // Build Vec once and reuse
    let vec: Vec<_> = gen.into_iter().take(5).collect();
    println!("{:?}", vec);
}

